+// Audit event
+// ---------------------------------------------------------------------------
+
+/// Audit event emitted for write operations (receipts).
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct PlannerAuditEvent {
+    pub timestamp: String,
+    pub action: String,
+    #[serde(rename = "taskId", default, skip_serializing_if = "Option::is_none")]
+    pub task_id: Option<String>,
+    #[serde(rename = "planId")]
+    pub plan_id: String,
+    pub details: String,
+}
+
+impl PlannerAuditEvent {
+    /// Create a new audit event.
+    #[must_use]
+    pub fn new(
+        timestamp: impl Into<String>,
+        action: impl Into<String>,
+        plan_id: impl Into<String>,
+        details: impl Into<String>,
+    ) -> Self {
+        Self {
+            timestamp: timestamp.into(),
+            action: action.into(),
+            task_id: None,
+            plan_id: plan_id.into(),
+            details: details.into(),
+        }
+    }
+
+    /// Attach a task id to the audit event.
+    #[must_use]
+    pub fn with_task_id(mut self, task_id: impl Into<String>) -> Self {
+        self.task_id = Some(task_id.into());
+        self
+    }
+}
+
+impl fmt::Display for PlannerAuditEvent {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        write!(
+            f,
+            "[{}] {} plan={} task={} {}",
+            self.timestamp,
+            self.action,
+            self.plan_id,
+            self.task_id.as_deref().unwrap_or("none"),
+            self.details,
+        )
+    }
+}
